<?php declare(strict_types=1); namespace App\Http\Requests\Payroll; use Illuminate\Foundation\Http\FormRequest; class StorePayrollComponentRequest extends FormRequest{public function authorize():bool{return $this->user()->can('payroll-components.manage');} public function rules():array{return ['name'=>'required|string|max:150','code'=>'required|string|max:50','component_type'=>'required|in:earning,deduction','calculation_type'=>'required|in:fixed,percentage,attendance,manual,controlled_formula','default_amount'=>'nullable|integer|min:0','percentage'=>'nullable|numeric|min:0','notes'=>'nullable|string'];}}
